import sys

class Solution:
    def numEnclaves(self, grid: list[list[int]]) -> int:
        m, n = len(grid), len(grid[0])
        directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]

        def dfs(r, c):
            if 0 <= r < m and 0 <= c < n and grid[r][c] == 0:
                grid[r][c] = -1
                for dr, dc in directions:
                    dfs(r + dr, c + dc)

        # Mark all the lands connected to the boundary as -1
        for i in range(m):
            dfs(i, 0)
            dfs(i, n - 1)
        for j in range(n):
            dfs(0, j)
            dfs(m - 1, j)

        # Count the number of enclaves
        count = 0
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 0:
                    count += 1
        return count

